class Idempotency {
  static String key({String? seed}) {
    final now = DateTime.now().toUtc().toIso8601String();
    final raw = '${seed ?? ''}|$now|${_rand()}';
    return sha256.convert(utf8.encode(raw)).toString();
  }

  static String _rand() => '${DateTime.now().microsecondsSinceEpoch}${Platform.operatingSystem}';
}

