class InAppPurchaseService {
  final InAppPurchase _iap = InAppPurchase.instance;
  final PaymentBackendClient backend;
  final bool enableLogs;

  StreamSubscription<List<PurchaseDetails>>? _sub;

  final StreamController<PurchaseDetails> _purchaseController = StreamController.broadcast();
  Stream<PurchaseDetails> get purchases => _purchaseController.stream;

  InAppPurchaseService({required this.backend, this.enableLogs = kDebugMode});

  Future<void> init() async {
    final available = await _iap.isAvailable();
    if (!available) {
      throw PaymentException('iap_unavailable', 'In-app purchases are not available on this device');
    }

    if (Platform.isIOS) {
      final iosPlatformAddition = _iap.getPlatformAddition<InAppPurchaseStoreKitPlatformAddition>();
      await iosPlatformAddition.setDelegate(_IapPaymentQueueDelegate());
    }

    _sub?.cancel();
    _sub = _iap.purchaseStream.listen(_onPurchaseUpdate, onError: (e) {
      if (enableLogs) debugPrint('IAP stream error: $e');
    });
  }

  Future<void> dispose() async {
    await _sub?.cancel();
    _sub = null;
    if (Platform.isIOS) {
      final iosPlatformAddition = _iap.getPlatformAddition<InAppPurchaseStoreKitPlatformAddition>();
      await iosPlatformAddition.setDelegate(null);
    }
    await _purchaseController.close();
  }

  Future<List<ProductDetails>> queryProducts(Set<String> productIds) async {
    final response = await _iap.queryProductDetails(productIds);
    if (response.error != null) {
      throw PaymentException('iap_query_failed', response.error!.message, response.error);
    }
    return response.productDetails;
  }

  Future<void> buyConsumable(ProductDetails product, {String? applicationUserName}) async {
    final param = PurchaseParam(productDetails: product, applicationUserName: applicationUserName);
    final ok = await _iap.buyConsumable(purchaseParam: param, autoConsume: Platform.isAndroid);
    if (!ok) throw PaymentException('iap_buy_failed', 'Failed to start consumable purchase flow');
  }

  Future<void> buyNonConsumable(ProductDetails product, {String? applicationUserName}) async {
    final param = PurchaseParam(productDetails: product, applicationUserName: applicationUserName);
    final ok = await _iap.buyNonConsumable(purchaseParam: param);
    if (!ok) throw PaymentException('iap_buy_failed', 'Failed to start non-consumable purchase flow');
  }

  Future<void> restorePurchases() async {
    await _iap.restorePurchases();
  }

  Future<PaymentResult> verifyAndFinish(PurchaseDetails purchase, {Map<String, dynamic>? metadata}) async {
    if (purchase.status == PurchaseStatus.pending) {
      return const PaymentResult(success: false, status: 'pending');
    }
    if (purchase.status == PurchaseStatus.error) {
      return PaymentResult(success: false, status: 'failed', message: purchase.error?.message);
    }

    final verificationData = purchase.verificationData.serverVerificationData;
    final source = purchase.verificationData.source;

    final platform = Platform.isIOS ? 'ios' : (Platform.isAndroid ? 'android' : 'unknown');
    final idempotencyKey = Idempotency.key(seed: purchase.purchaseID ?? purchase.productID);

    final result = await backend.verifyInAppPurchase(
      platform: platform,
      productId: purchase.productID,
      purchaseId: purchase.purchaseID ?? '',
      verificationData: verificationData,
      verificationSource: source,
      metadata: metadata,
      idempotencyKey: idempotencyKey,
    );

    if (purchase.pendingCompletePurchase) {
      await _iap.completePurchase(purchase);
    }

    if (Platform.isAndroid) {
      final androidAddition = _iap.getPlatformAddition<InAppPurchaseAndroidPlatformAddition>();
      if (purchase is GooglePlayPurchaseDetails) {
        if (!purchase.billingClientPurchase.isAcknowledged) {
          await androidAddition.acknowledgePurchase(purchase.purchaseID!);
        }
      }
    }

    return result;
  }

  void _onPurchaseUpdate(List<PurchaseDetails> purchases) {
    for (final p in purchases) {
      _purchaseController.add(p);
    }
  }
}

