class PaymentProcessor {
  final PaymentConfig config;
  final PaymentBackendClient backend;
  final InAppPurchaseService iap;

  PaymentProcessor._(this.config, this.backend, this.iap);

  static Future<PaymentProcessor> create(PaymentConfig config) async {
    final backend = PaymentBackendClient(config);
    final iap = InAppPurchaseService(backend: backend, enableLogs: config.enableLogs);
    await iap.init();
    return PaymentProcessor._(config, backend, iap);
  }

  Future<void> dispose() async {
    await iap.dispose();
    backend.dispose();
  }

  Future<PaymentResult> payWithApplePay({
    required Money amount,
    required CustomerInfo customer,
    required String label,
    Map<String, dynamic>? metadata,
  }) async {
    if (!Platform.isIOS) throw PaymentException('unsupported_platform', 'Apple Pay requires iOS');
    final merchantId = config.merchantIdApplePay;
    if (merchantId == null || merchantId.isEmpty) {
      throw PaymentException('config_missing', 'merchantIdApplePay is required');
    }
    final merchantName = config.merchantName ?? 'Merchant';
    final countryCode = config.countryCode ?? 'US';
    final currencyCode = config.currencyCode ?? amount.currency;

    final idempotencyKey = Idempotency.key(seed: '${customer.customerId}|applepay|${amount.amountMinor}');
    final intent = await backend.createIntent(
      PaymentIntentRequest(amount: amount, customer: customer, method: PaymentMethodType.applePay, metadata: metadata),
      idempotencyKey: idempotencyKey,
    );

    final token = await WalletPay.requestApplePayToken(
      merchantId: merchantId,
      merchantName: merchantName,
      countryCode: countryCode,
      currencyCode: currencyCode,
      amountMinor: amount.amountMinor,
      label: label,
    );

    return backend.confirmIntent(
      intentId: intent.intentId,
      method: PaymentMethodType.applePay,
      payload: {
        'walletToken': token,
        'clientSecret': intent.clientSecret,
      },
      idempotencyKey: idempotencyKey,
    );
  }

  Future<PaymentResult> payWithGooglePay({
    required Money amount,
    required CustomerInfo customer,
    required String label,
    String? gateway,
    String? gatewayMerchantId,
    Map<String, dynamic>? metadata,
  }) async {
    if (!Platform.isAndroid) throw PaymentException('unsupported_platform', 'Google Pay requires Android');
    final merchantName = config.merchantName ?? 'Merchant';
    final countryCode = config.countryCode ?? 'US';
    final currencyCode = config.currencyCode ?? amount.currency;

    final idempotencyKey = Idempotency.key(seed: '${customer.customerId}|googlepay|${amount.amountMinor}');
    final intent = await backend.createIntent(
      PaymentIntentRequest(amount: amount, customer: customer, method: PaymentMethodType.googlePay, metadata: metadata),
      idempotencyKey: idempotencyKey,
    );

    final token = await WalletPay.requestGooglePayToken(
      merchantName: merchantName,
      countryCode: countryCode,
      currencyCode: currencyCode,
      amountMinor: amount.amountMinor,
      label: label,
      gateway: gateway,
      gatewayMerchantId: gatewayMerchantId,
    );

    return backend.confirmIntent(
      intentId: intent.intentId,
      method: PaymentMethodType.googlePay,
      payload: {
        'walletToken': token,
        'clientSecret': intent.clientSecret,
      },
