  }

  Future<PaymentResult> startCardPayment({
    required Money amount,
    required CustomerInfo customer,
    required Map<String, dynamic> cardTokenPayload,
    Map<String, dynamic>? metadata,
  }) async {
    final idempotencyKey = Idempotency.key(seed: '${customer.customerId}|card|${amount.amountMinor}');
    final intent = await backend.createIntent(
